import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    min_time = float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        total_time = np.linalg.norm(cur_truck_pos - customer)  # calculate direct distance to customer

        for truck_pos in all_truck_pos:
            if truck_pos is not cur_truck_pos:
                time_to_other_truck = np.linalg.norm(truck_pos - customer)
                total_time += time_to_other_truck

        if total_time < min_time:
            min_time = total_time
            best_node = i

    return best_node
